from collections import deque
class Solution:
    def assignEdgeWeights(self, edges, queries):
        MOD = 10**9 + 7
        n = len(edges) + 1
        adj = [[] for _ in range(n + 1)]
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)
        LOG = max(1, (n).bit_length())
        depth = [0] * (n + 1)
        up = [[0] * (n + 1) for _ in range(LOG)]
        depth[1] = 0
        up[0][1] = 1
        visited = [False] * (n + 1)
        visited[1] = True
        dq = deque([1])
        while dq:
            x = dq.popleft()
            for y in adj[x]:
                if not visited[y]:
                    visited[y] = True
                    depth[y] = depth[x] + 1
                    up[0][y] = x
                    dq.append(y)
        for k in range(1, LOG):
            row = up[k]
            prev = up[k - 1]
            for node in range(1, n + 1):
                row[node] = prev[prev[node]]
        def lca(a, b):
            if depth[a] < depth[b]:
                a, b = b, a
            diff = depth[a] - depth[b]
            for k in range(LOG):
                if (diff >> k) & 1:
                    a = up[k][a]
            if a == b:
                return a
            for k in range(LOG - 1, -1, -1):
                if up[k][a] != up[k][b]:
                    a = up[k][a]
                    b = up[k][b]
            return up[0][a]
        res = []
        for u, v in queries:
            w = lca(u, v)
            d = depth[u] + depth[v] - 2 * depth[w]
            res.append(0 if d == 0 else pow(2, d - 1, MOD))
        return res

