var assignEdgeWeights = function(edges, queries) {
    const MOD = 1000000007n;
    const n = edges.length + 1;
    const adj = Array.from({ length: n + 1 }, () => []);
    for (const [u, v] of edges) { adj[u].push(v); adj[v].push(u); }
    let LOG = 1;
    while ((1 << LOG) <= n) LOG++;
    const depth = new Array(n + 1).fill(0);
    const up = Array.from({ length: LOG }, () => new Array(n + 1).fill(0));
    const visited = new Array(n + 1).fill(false);
    visited[1] = true; up[0][1] = 1;
    const q = [1];
    let head = 0;
    while (head < q.length) {
        const x = q[head++];
        for (const y of adj[x]) {
            if (!visited[y]) { visited[y] = true; depth[y] = depth[x] + 1; up[0][y] = x; q.push(y); }
        }
    }
    for (let k = 1; k < LOG; k++) {
        for (let node = 1; node <= n; node++) up[k][node] = up[k - 1][up[k - 1][node]];
    }
    function lca(a, b) {
        if (depth[a] < depth[b]) { const t = a; a = b; b = t; }
        let diff = depth[a] - depth[b];
        for (let k = 0; k < LOG; k++) if ((diff >> k) & 1) a = up[k][a];
        if (a === b) return a;
        for (let k = LOG - 1; k >= 0; k--) if (up[k][a] !== up[k][b]) { a = up[k][a]; b = up[k][b]; }
        return up[0][a];
    }
    function powmod(e) {
        let base = 2n, r = 1n, ee = BigInt(e);
        while (ee > 0n) { if (ee & 1n) r = (r * base) % MOD; base = (base * base) % MOD; ee >>= 1n; }
        return r;
    }
    const res = [];
    for (const [u, v] of queries) {
        const w = lca(u, v);
        const d = depth[u] + depth[v] - 2 * depth[w];
        res.push(d === 0 ? 0 : Number(powmod(d - 1)));
    }
    return res;
};
